    #[tokio::test]
    async fn test_vector_retriever_rbac_filtering() {
        let dir = tempfile::tempdir().unwrap();
        let store = Arc::new(LiteStore::open(dir.path(), 3).unwrap()) as Arc<dyn QueryableStore>;
        let engine = Arc::new(MockEngine) as Arc<dyn InferenceEngine>;
        store.init_schema().await.unwrap();

        let mut e = KnowledgeEntry::new("secret".into(), "scope-a".into(), "v1".into())
            .with_embedding(vec![1.0, 0.0, 0.0]);
        e.entry_status = EntryStatus::Merged;
        store.insert(&e).await.unwrap();

        let retriever = VectorRetriever::new(store, engine);
        let opts = RetrievalOpts {
            limit: 10,
            permissions: Some(AgentPermission::ReadWrite { scopes: vec!["scope-b".into()] }),
            ..Default::default()
        };

        // Agent only has access to scope-b, searching scope-a should return empty
        let result = retriever.retrieve("query", "scope-a", &opts).await.unwrap();
        assert_eq!(result.results.len(), 0);
    }
